\n              imageBase64: imageBase64,\n              imageUrl: imageUrl,\n            );\n          }\n\n          return AlertDialog(\n            backgroundColor: colorScheme.surface,\n            surfaceTintColor: Colors.transparent,\n            shape: RoundedRectangleBorder(\n              borderRadius: BorderRadius.circular(28),\n            ),\n            title: Text(\n              context.l10n!.addPlaylist,\n              style: TextStyle(\n                color: colorScheme.onSurface,\n                fontWeight: FontWeight.w600,\n              ),\n            ),\n            content: SingleChildScrollView(\n              child: Column(\n                mainAxisSize: MainAxisSize.min,\n                children: <Widget>[\n                  Container(\n                    decoration: BoxDecoration(\n                      color: colorScheme.surfaceContainerLow,\n                      borderRadius: BorderRadius.circular(16),\n                    ),\n                    padding: const EdgeInsets.all(4),\n                    child: Row(\n                      children: [\n                        Expanded(\n                          child: GestureDetector(\n                            onTap: () {\n                              dialogSetState(() {\n                                isYouTubeMode = true;\n                                id = '';\n                                customPlaylistName = '';\n                                imageUrl = null;\n                                imageBase64 = null;\n                              });\n                            },\n                            child: AnimatedContainer(\n                              duration: const Duration(milliseconds: 200),\n                              padding: const EdgeInsets.symmetric(vertical: 12),\n                              decoration: BoxDecoration(\n                                color: isYouTubeMode\n                                    ? colorScheme.primaryContainer\n                                    : Colors.transparent,\n                                borderRadius: BorderRadius.circular(12),\n                              ),\n                              child: Row(\n                                mainAxisAlignment: MainAxisAlignment.center,\n                                children: [\n                                  Icon(\n                                    FluentIcons.globe_20_filled,\n                                    size: 20,\n                                    color: isYouTubeMode\n                                        ? colorScheme.onPrimaryContainer\n                                        : colorScheme.onSurfaceVariant,\n                                  ),\n                                  const SizedBox(width: 8),\n                                  Text(\n                                    'YouTube',\n                                    style: TextStyle(\n                                      color: isYouTubeMode\n                                          ? colorScheme.onPrimaryContainer\n                                          : colorScheme.onSurfaceVariant,\n                                      fontWeight: isYouTubeMode\n                                          ? FontWeight.w600\n                                          : FontWeight.w500,\n                                    ),\n                                  ),\n                                ],\n                              ),\n                            ),\n                          ),\n                        ),\n                        Expanded(\n                          child: GestureDetector(\n                            onTap: () {\n                              dialogSetState(() {\n                                isYouTubeMode = false;\n                                id = '';\n                                customPlaylistName = '';\n                                imageUrl = null;\n                                imageBase64 = null;\n                              });\n                            },\n                            child: AnimatedContainer(\n                              duration: const Duration(milliseconds: 200),\n                              padding: const EdgeInsets.symmetric(vertical: 12),\n                              decoration: BoxDecoration(\n                                color: !isYouTubeMode\n                                    ? colorScheme.primaryContainer\n                                    : Colors.transparent,\n                                borderRadius: BorderRadius.circular(12),\n                              ),\n                              child: Row(\n                                mainAxisAlignment: MainAxisAlignment.center,\n                                children: [\n                                  Icon(\n                                    FluentIcons.person_20_filled,\n                                    size: 20,\n                                    color: !isYouTubeMode\n                                        ? colorScheme.onPrimaryContainer\n                                        : colorScheme.onSurfaceVariant,\n                                  ),\n                                  const SizedBox(width: 8),\n                                  Text(\n                                    context.l10n!.custom,\n                                    style: TextStyle(\n                                      color: !isYouTubeMode\n                                          ? colorScheme.onPrimaryContainer\n                                          : colorScheme.onSurfaceVariant,\n                                      fontWeight: !isYouTubeMode\n                                          ? FontWeight.w600\n                                          : FontWeight.w500,\n                                    ),\n                                  ),\n                                ],\n                              ),\n                            ),\n                          ),\n                        ),\n                      ],\n                    ),\n                  ),\n                  const SizedBox(height: 20),\n                  if (isYouTubeMode)\n                    TextField(\n                      decoration: InputDecoration(\n                        labelText: context.l10n!.youtubePlaylistLinkOrId,\n                        prefixIcon: Icon(\n                          FluentIcons.link_20_regular,\n                          color: colorScheme.onSurfaceVariant,\n                        ),\n                        border: OutlineInputBorder(\n                          borderRadius: BorderRadius.circular(12),\n                        ),\n                        filled: true,\n                        fillColor: colorScheme.surfaceContainerLow,\n                      ),\n                      onChanged: (value) {\n                        id = value;\n                      },\n                    )\n                  else ...[\n                    TextField(\n                      decoration: InputDecoration(\n                        labelText: context.l10n!.customPlaylistName,\n                        prefixIcon: Icon(\n                          FluentIcons.text_field_20_regular,\n                          color: colorScheme.onSurfaceVariant,\n                        ),\n                        border: OutlineInputBorder(\n                          borderRadius: BorderRadius.circular(12),\n                        ),\n                        filled: true,\n                        fillColor: colorScheme.surfaceContainerLow,\n                      ),\n                      autofocus: true,\n                      onChanged: (value) {\n                        customPlaylistName = value;\n                      },\n                    ),\n                    if (imageBase64 == null) ...[\n                      const SizedBox(height: 12),\n                      TextField(\n                        decoration: InputDecoration(\n                          labelText: context.l10n!.customPlaylistImgUrl,\n                          prefixIcon: Icon(\n                            FluentIcons.image_20_regular,\n                            color: colorScheme.onSurfaceVariant,\n                          ),\n                          border: OutlineInputBorder(\n                            borderRadius: BorderRadius.circular(12),\n                          ),\n                          filled: true,\n                          fillColor: colorScheme.surfaceContainerLow,\n                        ),\n                        onChanged: (value) {\n                          imageUrl = value;\n                          imageBase64 = null;\n                          dialogSetState(() {});\n                        },\n                      ),\n                    ],\n                    const SizedBox(height: 12),\n                    if (imageUrl == null) ...[\n                      buildImagePickerRow(\n                        context,\n                        _pickImage,\n                        imageBase64 != null,\n                      ),\n                      _imagePreview(),\n                    ],\n                  ],\n                ],\n              ),\n            ),\n            actions: <Widget>[\n              TextButton(\n                onPressed: () => Navigator.pop(context),\n                child: Text(\n                  context.l10n!.cancel,\n                  style: TextStyle(color: colorScheme.onSurfaceVariant),\n                ),\n              ),\n              FilledButton.icon(\n                onPressed: () async {\n                  if (isYouTubeMode && id.isNotEmpty) {\n                    final result = await addUserPlaylist(id, context);\n                    if (context.mounted) showToast(context, result);\n                    \n                    if (songToAdd != null && context.mounted) {\n                       if (userPlaylists.value.isNotEmpty) {\n                           final newPlaylist = userPlaylists.value.last;\n                       }\n                    }\n                    if (!context.mounted) return;\n                    Navigator.pop(context);\n                  } else if (!isYouTubeMode && customPlaylistName.isNotEmpty) {\n                    final oldLength = userCustomPlaylists.value.length;\n                    final result = createCustomPlaylist(\n                      customPlaylistName.trim(),\n                      imageBase64 ?? imageUrl,\n                      context,\n                    );\n                    if (context.mounted) {\n                        showToast(context, result);\n                    }\n                    \n                    if (songToAdd != null && userCustomPlaylists.value.length > oldLength) {\n                      final newPlaylist = userCustomPlaylists.value.last;\n                      if (context.mounted) {\n                        final addResult = addSongInCustomPlaylist(\n                          context,\n                          newPlaylist['ytid'],\n                          songToAdd,\n                        );\n                        showToast(context, addResult);\n                      }\n                    }\n                    if (!context.mounted) return;\n                    Navigator.pop(context);\n                  } else {\n                    showToast(\n                      context,\n                      '${context.l10n!.provideIdOrNameError}.',\n                    );\n                  }\n                },\n                icon: const Icon(FluentIcons.add_20_filled),\n                label: Text(context.l10n!.add),\n              ),\n            ],\n          );\n        },\n      );\n    },\n  );\n}\n